import React from 'react';

const entries = [
  {
    degree: 'Bachelor of Science in Information Technology',
    major: 'Major in Web Technology',
    school: 'Your University Name',
    year: '2023 – Present',
  },
  {
    degree: 'Senior High School',
    major: 'STEM / ICT Track',
    school: 'Your Senior High School',
    year: '2021 – 2023',
  },
];

const Education = () => (
  <section
    id="Education"
    style={{ background: '#0a192f', fontFamily: "'Orbitron', sans-serif" }}
    className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
  >
    <h1 className="text-white text-4xl font-bold mb-12">Education</h1>

    <div className="w-full max-w-2xl flex flex-col gap-5">
      {entries.map((e, i) => (
        <div
          key={i}
          style={{
            background: '#f8f9fa',
            borderLeft: '5px solid #0d6efd',
            borderRadius: '12px',
            padding: '20px',
          }}
        >
          <h3 style={{ color: '#0b1f3a', fontWeight: 'bold' }}>{e.degree}</h3>
          <p>{e.major}</p>
          <p>{e.school}</p>
          <p>{e.year}</p>
        </div>
      ))}
    </div>
  </section>
);

export default Education;
